import React, { useEffect, useState } from "react";

function Bookings() {

  const [bookings, setBookings] = useState([]);

  useEffect(() => {
    fetch("http://localhost:3000/bookings")
      .then(res => res.json())
      .then(data => setBookings(data));
  }, []);

  return (

    <div>

      <h1>Bookings</h1>

      <table border="1">

        <thead>
          <tr>
            <th>ID</th>
            <th>Field</th>
            <th>Date</th>
            <th>Time</th>
          </tr>
        </thead>

        <tbody>

          {bookings.map(booking => (
            <tr key={booking.id}>
              <td>{booking.id}</td>
              <td>{booking.field_id}</td>
              <td>{booking.date}</td>
              <td>{booking.time}</td>
            </tr>
          ))}

        </tbody>

      </table>

    </div>

  );
}

export default Bookings;
